  ('generalpolice-410e2224-moex-00005', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-de0a21a2', 'sub-generalpolice-410e2224-02', NULL, 'essay', '公務員甲因投資失敗，欠下鉅額債務，某日知悉經營貴金屬鑑定的好友
乙，正好於家中保管客戶 A的高價金屬，甲告訴乙，該貴金屬依照 A的
經營模式一定有保險，不如想出一個方法，對 A謊稱該批貴金屬遭人搶
劫，實際上由甲變賣，利益兩人均分，對 A來說也不會有太多損失。乙
告訴甲，可以將該批貴金屬拿一些出來，客戶應該不會發現，但謊稱整
批被搶走，很難說得過去。兩人商議後，同意由乙取出部分貴金屬（市
價約新臺幣 200萬元）藉由甲的人脈關係賣出，獲取金額由乙拿六成，
甲拿四成。因為在交易市場中，買家丙私下辨識出該貴金屬為 A所有，
且甲無法交代貴金屬來源，實際賣得總價只有 50萬，甲、乙依兩人約定
朋分贓款。
數月後甲仍需錢孔急，甲到乙的辦公室向乙借錢，稱討債公司揚言，若
不還錢，將加害甲的家人。乙考慮數日後，仍拒絕借錢給甲。另一方面，
乙心中確實不忍甲的家人遭受危難，乙將甲約至辦公室，對甲婉轉說明
自己手上也沒有多餘現金可供週轉，無法借錢給甲。乙以有要事處理為
由要外出一趟，離開辦公室前將家中存放貴金屬之保險箱的鑰匙放置桌
上，心想如果甲識得該鑰匙並且能夠使用鑰匙拿走貴金屬，也算幫甲一
個忙。甲果然認得該鑰匙為乙家中保險箱鑰匙，趁辦公室四下無人，甲
將鑰匙放進口袋後即離開。當天夜裡，甲攜帶鑰匙潛入乙的家中，開啟
保險箱並將裡面所存放之 A的貴金屬一掃而空。試問甲、乙的行為依刑
法如何評價？（50 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "a91534b7814d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00006', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-de0a21a2', 'sub-generalpolice-410e2224-02', NULL, 'essay', '警察在例行巡邏時，發現前科累累，甫出獄的張三神情可疑地在雜貨店
門口張頭探腦，於是向前盤查，因而發現其攜帶有槍枝，並以現行犯逮
捕張三。逮捕後，警察搜索張三隨身攜帶的背包，發現有毒品。請問，
警察所發現的槍枝及毒品，有無證據能力？應如何判斷？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "a91534b7814d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00007', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-de0a21a2', 'sub-generalpolice-410e2224-02', NULL, 'essay', '地方檢察署檢察官張三對於李四的案件提起公訴，法院諭知無罪判決，
張三不服，提起上訴。後張三調任高等檢察署，該案件輪分至張三，由
其辦理。請問，張三是否應迴避？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "a91534b7814d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00008', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '有關禁止法律溯及既往原則與過渡條款，下列敘述何者正確？', '["限制基本權利之法律，若適用於該法律施行前已終結之事件，乃憲法所絕對不許", "基於禁止法律溯及既往原則，對人民有利之法律，不得適用於該法律施行前已終結之事件", "基於禁止法律溯及既往原則，法律不得適用於施行前已發生，施行後繼續存在之法律關係", "立法者制定新法，若應設卻未設過渡條款適度排除新法之適用範圍，此一法律漏洞仍有由司法機關 補充之可能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00009', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '依據憲法增修條文規定，有關基本國策，國家對於公營金融機構之管理，應本下列何種原則？', '["社會平等", "企業化經營", "組織現代化", "提升競爭力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00010', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '政黨為人民之政治性結社團體，有關政黨與結社自由，下列敘述何者錯誤？', '["基於結社自由，人民得自由選擇加入或退出特定政黨", "政黨財產之使用、收益及處分，受財產權及結社自由之憲法保障", "政黨就其存續、內部之組織與運作以及對外活動等，不受國家恣意之干預", "政黨於民主政治運作有其重要性與必要性，故國家不得以任何理由解散政黨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00011', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '所得稅法將軍人、國小教師原本免繳所得稅之規定，改為有所得即應繳稅，屬於憲法平等原則對何國 家機關的拘束？', '["對監察院之拘束", "對司法院之拘束", "對行政院之拘束", "對立法院之拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00012', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '下列何者與憲法第15條保障之工作權無關？', '["老年年金制度", "限制醫師藥品調劑權", "勞資爭議處理機制", "對童工的相關保護規範"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00013', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '依司法院釋字第490號解釋，有關「中華民國男子依法皆有服兵役之義務」規定，下列敘述何者 錯誤？', '["基於憲法平等原則的要求，應將女子排除於兵役義務之外", "人民履行兵役義務的方式，應由立法者決定", "人民有服兵役之義務，此為憲法明文規定", "關於服兵役之重要事項，立法者應斟酌國家安全之需要，予以規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00014', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-114-3d2b73b6', 'sub-generalpolice-410e2224-03', NULL, 'single_choice', '有關基本權，下列敘述何者正確？', '["依司法院釋字第748號解釋，若不許同性結婚，有違憲法增修條文消除性別歧視之規定", "秘密通訊自由屬於隱私權保障之具體態樣之一", "凡自然人均享有基本權，因此外國人亦可享有所有基本權", "國家基於對工作權之保障，有提供人民工作機會之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:37+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "306", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL)
